# Problem: Implement synchronous simulations of common asyncio concurrency patterns
# including task pooling, work queues, pipelines, fan-out/fan-in, debouncing, and batching.
#
# Approach: Each class is a straightforward synchronous implementation of its pattern.
# - TaskPool: stores callables, executes in batches based on max_concurrent
# - WorkQueue: wraps a list with bounded capacity
# - Pipeline: chains functions, threading output to input
# - FanOutFanIn: sends same data to all workers, merges results
# - Debouncer: tracks last call time per key using time.time()
# - Batcher: buffers items, processes when batch_size reached
#
# Time complexity: All operations are O(n) where n is number of items/tasks.
# Space complexity: O(n) for storing items/tasks/results.
#
# Key steps:
# 1. TaskPool batches tasks into groups of max_concurrent (or all at once if 0)
# 2. WorkQueue enforces max_size capacity (0 = unlimited)
# 3. Pipeline threads data through steps, recording each step's input/output
# 4. FanOutFanIn passes identical data to every worker, then merges
# 5. Debouncer skips calls if key was called within delay seconds
# 6. Batcher triggers processor when buffer reaches batch_size

import time
from typing import Any, Callable


class TaskPool:

    def __init__(self, max_concurrent: int = 0):
        self.max_concurrent = max_concurrent
        self.tasks = []  # list of (func, args) tuples
        self.counter = 0

    def submit(self, func: Callable, *args) -> str:
        self.counter += 1
        task_id = f"task-{self.counter}"
        self.tasks.append((task_id, func, args))
        return task_id

    def run_all(self) -> list[dict]:
        results = []
        if self.max_concurrent <= 0:
            # Unlimited: all tasks in batch 1
            for task_id, func, args in self.tasks:
                try:
                    result = func(*args)
                    results.append({"task_id": task_id, "result": result, "error": None, "batch": 1})
                except Exception as e:
                    results.append({"task_id": task_id, "result": None, "error": str(e), "batch": 1})
        else:
            # Process in batches of max_concurrent
            batch_num = 1
            for i in range(0, len(self.tasks), self.max_concurrent):
                batch = self.tasks[i:i + self.max_concurrent]
                for task_id, func, args in batch:
                    try:
                        result = func(*args)
                        results.append({"task_id": task_id, "result": result, "error": None, "batch": batch_num})
                    except Exception as e:
                        results.append({"task_id": task_id, "result": None, "error": str(e), "batch": batch_num})
                batch_num += 1
        return results


class WorkQueue:

    def __init__(self, max_size: int = 0):
        self.max_size = max_size
        self.items = []

    def put(self, item: Any) -> bool:
        if self.max_size > 0 and len(self.items) >= self.max_size:
            return False
        self.items.append(item)
        return True

    def get(self) -> Any:
        if not self.items:
            raise IndexError("Queue is empty")
        return self.items.pop(0)

    def peek(self) -> Any:
        if not self.items:
            raise IndexError("Queue is empty")
        return self.items[0]

    def size(self) -> int:
        return len(self.items)

    def is_empty(self) -> bool:
        return len(self.items) == 0

    def is_full(self) -> bool:
        if self.max_size == 0:
            return False  # unlimited capacity
        return len(self.items) >= self.max_size

    def drain(self) -> list:
        items = list(self.items)
        self.items.clear()
        return items


class Pipeline:

    def __init__(self):
        self.steps = []

    def add_step(self, name: str, func: Callable) -> 'Pipeline':
        self.steps.append((name, func))
        return self  # enable method chaining

    def process(self, data: Any) -> dict:
        steps_log = []
        current = data
        for name, func in self.steps:
            step_input = current
            current = func(current)
            steps_log.append({"name": name, "input": step_input, "output": current})
        return {"result": current, "steps": steps_log}

    def process_batch(self, items: list) -> list[dict]:
        return [self.process(item) for item in items]


class FanOutFanIn:

    def __init__(self, workers: list[Callable], merger: Callable):
        self.workers = workers
        self.merger = merger

    def execute(self, data: Any) -> dict:
        # Send same data to all workers
        worker_results = [worker(data) for worker in self.workers]
        merged = self.merger(worker_results)
        return {"worker_results": worker_results, "merged": merged}


class Debouncer:

    def __init__(self, delay: float):
        self.delay = delay
        self.last_call_time = {}  # key -> last execution timestamp
        self.call_counts = {}     # key -> number of actual executions

    def call(self, key: str, func: Callable) -> Any | None:
        now = time.time()
        last = self.last_call_time.get(key)
        if last is not None and (now - last) < self.delay:
            return None  # within debounce window, skip
        self.last_call_time[key] = now
        self.call_counts[key] = self.call_counts.get(key, 0) + 1
        return func()

    def get_call_count(self, key: str) -> int:
        return self.call_counts.get(key, 0)


class Batcher:

    def __init__(self, batch_size: int, processor: Callable):
        self.batch_size = batch_size
        self.processor = processor
        self.buffer = []

    def add(self, item: Any) -> list | None:
        self.buffer.append(item)
        if len(self.buffer) >= self.batch_size:
            batch = list(self.buffer)
            self.buffer.clear()
            return self.processor(batch)
        return None

    def flush(self) -> list | None:
        if not self.buffer:
            return None
        batch = list(self.buffer)
        self.buffer.clear()
        return self.processor(batch)
